# LLM-as-judge evaluation
import openai

def llm_judge(question: str, reference: str, prediction: str, model='gpt-4o') -> dict:
    prompt = f"""
Rate the following answer on a scale of 1-10 for accuracy and helpfulness.
Question: {question}
Reference answer: {reference}
Model answer: {prediction}

Respond with JSON: {{"score": int, "reasoning": str}}"""

    response = openai.chat.completions.create(
        model=model,
        messages=[{'role': 'user', 'content': prompt}],
        response_format={'type': 'json_object'}
    )
    return response.choices[0].message.content

# Batch evaluation
def evaluate_model(test_set, model, judge_model='gpt-4o'):
    scores = []
    for item in test_set:
        pred = model.generate(item['question'])
        result = llm_judge(item['question'], item['reference'], pred, judge_model)
        scores.append(result['score'])
    return {'mean': sum(scores)/len(scores), 'scores': scores}
